{
 "title": "S3 बकेट नीति",
  "group": "S3 सुरक्षा",
  "options": [
    {
      "text": "नए बकेट को सार्वजनिक बनाएं",
      "hint": "सबसे कम अधिकार, पहले."
    },
    {
      "text": "S3 को ऑन‑प्रेमाइसेस ले जाएँ ताकि ACLs पर पूरी नियंत्रण हो सके"
    },
    {
      "text": "डेटा को निजी ब्लॉकचेन पर ले जाएँ",
      "hint": "मजाक है, है ना?"
    },
    {
      "text": "सबसे कम अधिकार सिद्धांत का उपयोग करें"
    },
    {
      "text": "आवश्यक पहुँच सुनिश्चित करने के लिए नीति वाइल्डकार्ड का उपयोग करें",
      "hint": "😯 नहीं!"
    }
  ],
  "questionProse": [
    "S3 बकेट अनुमतियों के लिए सुझाया गया तरीका क्या है?"
  ],
  "explanationProse": [
    "लगभग सभी सिस्टम में, \"सबसे कम अधिकार\" डिज़ाइन अपनाना सुरक्षा बढ़ाने और भविष्य के लिए तैयार रहने का मुख्य तरीका है। मौजूदा सिस्टम को लॉक‑डाउन करने की कोशिश उतनी ही कठिन है जितना पूरी इमारत को नई नींव पर ले जाना।\n\n    S3 बकेट भी इसका अपवाद नहीं हैं। सबसे कम अधिकार सिद्धांत लागू करने के लिए, पहले कोई अनुमति न दें और केवल आवश्यक पहुँच ही प्रदान करें। पहुँच नियंत्रित करने के लिए IAM रोल और नीतियों का उपयोग करें और नियमित रूप से बकेट अनुमतियों की ऑडिट करें।\n\n    सुरक्षा सर्वोत्तम अभ्यास:\n    - सबसे कम अधिकार सिद्धांत लागू करें\n    - कोई अनुमति न देकर शुरू करें\n    - केवल आवश्यक पहुँच प्रदान करें\n    - IAM रोल और नीतियों का उपयोग करें\n    - बकेट अनुमतियों की नियमित ऑडिट करें\n\n    अत्यधिक अनुमतियों से बचें जो संवेदनशील डेटा को उजागर कर सकते हैं।\n\n    [S3 Security Best Practices](https://aws.amazon.com/s3/security/)"
  ]
}
